root.js-content:
stp.writeLog("====012.001.03 Receive 012 from Corporate====");

var OurBIC=stp.getTSUBIC();
stp.writeLog("getTSUBIC="+OurBIC);
//generate TSU_SEQ_NUM for DO--S
stp.genDOTsuSeqNum(); 
//generate TSU_SEQ_NUM for DO--E 
var BYRBK_BIC =stp.getValue("/Document/BaselnReSubmissn/Baseln/BuyrBk","BIC");
var TSU_BYRBK_BIC = BYRBK_BIC[0];
stp.writeLog("TSU_BYRBK_BIC="+TSU_BYRBK_BIC);
var SELLRBK_BIC = stp.getValue("/Document/BaselnReSubmissn/Baseln/SellrBk","BIC");
var TSU_SELLRBK_BIC = SELLRBK_BIC[0];
stp.writeLog("TSU_SELLRBK_BIC="+TSU_SELLRBK_BIC);

stp.writeLog("Begin: FullPushThroughReportReSubmit");

var BIC = stp.getValue("/Document/BaselnReSubmissn/Baseln/SubmitrBaselnId/Submitr","BIC");
var RefId = stp.getValue("/Document/BaselnReSubmissn/Baseln/SubmitrBaselnId","Id");
    if (BIC.length == 1)
    {
        var Bool = stp.compareString(BIC[0],OurBIC);
        if (Bool == "false")
        {   stp.writeLog("ReSubmit 1 false");
            stp.updateFieldValue("","TSU_THEIR_BIC",BIC[0]);
            stp.updateFieldValue("","TSU_THEIR_REF",RefId[0]);
            stp.updateFieldValue("","TSU_OUR_BIC",OurBIC);
            stp.updateFieldValue("","TSU_OUR_REF",mainRef);
        }
        if (Bool == "true")
        {   stp.writeLog("ReSubmit 2 true");
            stp.updateFieldValue("","TSU_OUR_BIC",OurBIC);
            stp.updateFieldValue("","TSU_OUR_REF",RefId[0]);
        }
    }

    if (BIC.length == 2)
    {  
        var Bool2 = stp.compareString(BIC[0],OurBIC);
        var Bool3 = stp.compareString(BIC[1],OurBIC);
        if (Bool2 == "true")
        {
            stp.updateFieldValue("","TSU_OUR_BIC",BIC[0]);
            stp.updateFieldValue("","TSU_OUR_REF",RefId[0]);
            stp.updateFieldValue("","TSU_THEIR_BIC",BIC[1]);
            stp.updateFieldValue("","TSU_THEIR_REF",RefId[1]);
        }
        if (Bool3 == "true")
        {
            stp.updateFieldValue("","TSU_OUR_BIC",BIC[1]);
            stp.updateFieldValue("","TSU_OUR_REF",RefId[1]);
            stp.updateFieldValue("","TSU_THEIR_BIC",BIC[0]);
            stp.updateFieldValue("","TSU_THEIR_REF",RefId[0]);
        }
    }

stp.setAutoProcess(true);
// select the record need to process by TSU_TID by BU
var GetTxId = stp.getValue("/Document/BaselnReSubmissn/TxId","Id");
var bu = stp.getTSUUnitCode();
var fld_list  = stp.addFieldList(null,"C_MAIN_REF");
var sql_condition = stp.addSQLCondition(null,"TSU_TID",GetTxId[0]);
    sql_condition = stp.addSQLCondition(sql_condition,"C_UNIT_CODE",bu);
var result   = stp.executeQuery("TSUM_MASTER",fld_list,sql_condition);
var mainRef= stp.getDBFieldValue(result,"C_MAIN_REF");
stp.writeLog("mainRef="+mainRef);
stp.updateFieldValue("","C_MAIN_REF",mainRef);
stp.updateFieldValue("","C_TRX_REF",mainRef);   
stp.writeLog("Begin: Enter FullPushThroughReportReSubmit");
var OthrBkCtctPrsn = stp.getValue("/Document/BaselnReSubmissn/OthrBkCtctPrsn","BIC");
	if (OthrBkCtctPrsn[0] != undefined)
	{
		stp.updateFieldValue("/root/domData/R2InvolvedPartyInfo/OtherBk","TSU_CONT_ID",0);
	}

var Incotrmscd = stp.getValue("/Document/BaselnReSubmissn/Baseln/Goods/Incotrms","Cd");
var IncotrmsOthr = stp.getValue("/Document/BaselnReSubmissn/Baseln/Goods/Incotrms","Othr");
	if (Incotrmscd[0] != undefined || IncotrmsOthr[0] != undefined)
	{
		stp.updateFieldValue("/root/domData/R2Goods/Incoterms1","TSU_LNITMNB",0);
	}

var AdjstmntTp = stp.getValue("/Document/BaselnReSubmissn/Baseln/Goods/Adjstmnt","Tp");
var AdjstmntOthr = stp.getValue("/Document/BaselnReSubmissn/Baseln/Goods/Adjstmnt","OthrAdjstmntTp");
	if (AdjstmntTp[0] != undefined || AdjstmntOthr[0] != undefined)
	{
		stp.updateFieldValue("/root/domData/R2Goods/Adjustmtents","TSU_LNITMNB",0);
	}


// Calculate the Goods/Adjstmnt amount according to the direction;
var AdjstmntDrctn = stp.getValue("/Document/BaselnReSubmissn/Baseln/Goods/Adjstmnt","Drctn");
var AdjstmntAMT = stp.getValue("/Document/BaselnReSubmissn/Baseln/Goods/Adjstmnt","Amt");
var nlength = AdjstmntDrctn.length;
if (AdjstmntAMT[0] != undefined)
 {
	for(var k=0;k<nlength;k++)
	        {
	         stp.writeLog("AdjstmntDrctn:"+ AdjstmntDrctn[k]);
	         stp.writeLog("AdjstmntAMT:"+ AdjstmntAMT[k]);
	          var xpath2="/root/domData/R2Goods/Adjustmtents["+stp.toDouble(k+1)+"]";
	          var DRCTN = AdjstmntDrctn[k];
	          var AMOUNT = AdjstmntAMT[k];
	          stp.writeLog("DRCTN = "+ DRCTN);
	          stp.writeLog("AMOUNT"+AMOUNT);
	         if (DRCTN =='ADDD')
	         {
	         stp.updateFieldValue(xpath2,"TSU_IAFT_AMT_CAL",AMOUNT);
	         }    
	         if (DRCTN =='SUBS')
	         {
	         var Fuzhi ='-'+AMOUNT;
	         stp.writeLog("Fuzhi="+Fuzhi);
	         stp.updateFieldValue(xpath2,"TSU_IAFT_AMT_CAL",Fuzhi);
	         }  
	        }
        }

   // Calculate the Goods/LineItmDtls/Adjstmnt amount according to the direction; 
var LineAdjstmntDrctn = stp.getValue("/Document/BaselnReSubmissn/Baseln/Goods/LineItmDtls/Adjstmnt","Drctn");
var LineAdjstmntAMT = stp.getValue("/Document/BaselnReSubmissn/Baseln/Goods/LineItmDtls/Adjstmnt","Amt");
var mlength = LineAdjstmntDrctn.length;
if (LineAdjstmntAMT[0] != undefined)
{
	for(var j=0;j<mlength;j++)
	       {
	         var xpath="/root/domData/R2Goods/R2LineItemDetails7/Adjustmtents["+stp.toDouble(j+1)+"]";
	         var LDRCTN = LineAdjstmntDrctn[j];
	         var LAMOUNT = LineAdjstmntAMT[j];
	         if (LDRCTN =='ADDD')
	         {
			stp.updateFieldValue(xpath,"TSU_IAFT_AMT_CAL",LAMOUNT);
	         }    
	         if (LDRCTN =='SUBS')
	        {
	        var LineFuzhi ='-'+LAMOUNT;
			stp.updateFieldValue(xpath,"TSU_IAFT_AMT_CAL",LineFuzhi);
	        }  
	       }
       }


var FreightChg = stp.getValue("/Document/BaselnReSubmissn/Baseln/Goods/FrghtChrgs/Chrgs","Tp");
	if(FreightChg[0] != undefined)
	{
	stp.updateFieldValue("/root/domData/R2Goods/FrghtChrgs","TSU_LNITMNB",0);
	}

var TaxTp = stp.getValue("/Document/BaselnReSubmissn/Baseln/Goods/Tax","Tp");
	if(TaxTp[0] != undefined)
	{
	stp.updateFieldValue("/root/domData/R2Goods/Tax3","TSU_LNITMNB",0);
	}

// For delete the optional node which unexisted in the coming message;		
var BuyrSdSubmitgBk = stp.getValue("/Document/BaselnReSubmissn/Baseln/BuyrSdSubmitgBk","BIC");
var SellrSdSubmitgBk = stp.getValue("/Document/BaselnReSubmissn/Baseln/SellrSdSubmitgBk","BIC");
var BillTo = stp.getValue("/Document/BaselnReSubmissn/Baseln/BllTo/PstlAdr","Ctry");
var ShipTo = stp.getValue("/Document/BaselnReSubmissn/Baseln/ShipTo/PstlAdr","Ctry");
var Consignee = stp.getValue("/Document/BaselnReSubmissn/Baseln/Consgn/PstlAdr","Ctry");
if (BuyrSdSubmitgBk[0] == undefined)
{
	stp.deleNode("/root/domData/R2InvolvedPartyInfo","BuyrSdSubmitgBk");
}
if (SellrSdSubmitgBk[0] == undefined)
{
	stp.deleNode("/root/domData/R2InvolvedPartyInfo","SellrSdSubmitgBk");
}
if (BillTo[0] == undefined)
{
	stp.deleNode("/root/domData/R2InvolvedPartyInfo","BillTo");		    
}
if (ShipTo[0] == undefined)
{
	stp.deleNode("/root/domData/R2InvolvedPartyInfo","ShipTo");  
}
if (Consignee[0] == undefined)
{
	stp.deleNode("/root/domData/R2InvolvedPartyInfo","Consignee");
}

var InsrncDataSetReqrd  = stp.getValue("/Document/BaselnReSubmissn/Baseln/InsrncDataSetReqrd/Submitr","BIC");
if (InsrncDataSetReqrd[0] == undefined)
{
	stp.deleNode("/root/domData/R2DatasetRequired","InsuranceDataSetRequired");
}

var IBAN = stp.getValue("/Document/BaselnReSubmissn/Baseln/SttlmTerms/CdtrAcct/Id","IBAN");
var BBAN = stp.getValue("/Document/BaselnReSubmissn/Baseln/SttlmTerms/CdtrAcct/Id","BBAN");
var UPIC = stp.getValue("/Document/BaselnReSubmissn/Baseln/SttlmTerms/CdtrAcct/Id","UPIC");
var PrtryAcct = stp.getValue("/Document/BaselnReSubmissn/Baseln/SttlmTerms/CdtrAcct/Id/PrtryAcct","Id");
if (IBAN[0] == undefined && BBAN[0] == undefined && UPIC[0] == undefined && PrtryAcct[0] == undefined)
{
	stp.deleNode("/root/domData","R2SettlementTerms");
}

var IBAN = stp.getValue("/Document/BaselnReSubmissn/Baseln/PmtOblgtn/SttlmTerms/CdtrAcct/Id","IBAN");
var BBAN = stp.getValue("/Document/BaselnReSubmissn/Baseln/PmtOblgtn/SttlmTerms/CdtrAcct/Id","BBAN");
var UPIC = stp.getValue("/Document/BaselnReSubmissn/Baseln/PmtOblgtn/SttlmTerms/CdtrAcct/Id","UPIC");
var PrtryAcct = stp.getValue("/Document/BaselnReSubmissn/Baseln/PmtOblgtn/SttlmTerms/CdtrAcct/Id/PrtryAcct","Id");
if (IBAN[0] == undefined && BBAN[0] == undefined && UPIC[0] == undefined && PrtryAcct[0] == undefined)
{
	stp.deleNode("/root/domData/R2PaymentObligation","R2SettlementTerms2");
}

//finish delete node;

var PaymentTermsRe = stp.getRecords("R2PaymentTerms");
stp.writeLog("PaymentTermsRe.length = "+ PaymentTermsRe.length);
for (var i = 0; i<PaymentTermsRe.length;i++)
{
	var ref = "PMT" + (i+1);
	stp.writeLog("ref = "+ ref);
	stp.setDOValue(PaymentTermsRe[i],"TSU_IAFT_NO",ref);
}

var PmtTermOblgtnRe = stp.getRecords("R2PaymentObligation.PaymentTerms1");
stp.writeLog("PmtTermOblgtnRe.length = "+ PmtTermOblgtnRe.length);
for (var i = 0; i<PmtTermOblgtnRe.length;i++)
{
	var ref = "OBLGN" + (i+1);
	stp.writeLog("ref = "+ ref);
	stp.setDOValue(PmtTermOblgtnRe[i],"TSU_IAFT_NO",ref);
}

var SttlmTermsRe = stp.getRecords("R2SettlementTerms");
stp.writeLog("SttlmTermsRe.length = "+ SttlmTermsRe.length);
for (var i = 0; i<SttlmTermsRe.length;i++)
	{
	stp.updateFieldValue("/root/domData/R2SettlementTerms","TSU_IDX",0);
	}

stp.updateFieldValue("/root/domData","DELETE_ALL_DATA","Y");
stp.setFunc("InCoE012");
stp.writeLog("End: Enter Receive 012 from Corporate");

//Get Buyer/Seller/Bill To/Ship To/Consignee Names -S
stp.writeLog("TSU_BYRBK_BIC="+ TSU_BYRBK_BIC);
stp.updateFieldValue("/root/domData","TSU_BYRBK_BIC",TSU_BYRBK_BIC);
stp.SYS_getCUBK("TSU_BYRBK_BIC","TSU_BUYER_BK_BIC","/root/domData/R2InvolvedPartyInfo/BuyerBank");          // Get Buyerbk Name and ID from the Buyer BIC

stp.writeLog("TSU_SELLRBK_BIC:"+ TSU_SELLRBK_BIC);
stp.updateFieldValue("/root/domData","TSU_SELLRBK_BIC",TSU_SELLRBK_BIC);
stp.SYS_getCUBK("TSU_SELLRBK_BIC","TSU_SEL_BK_BIC","/root/domData/R2InvolvedPartyInfo/SellerBank");    // Get Sellerbk Name and ID from the Seller BIC

var Buyer  =stp.getValue("/Document/BaselnReSubmissn/Baseln/Buyr","Nm");
var Buyer = Buyer[0];
stp.writeLog("Buyer = "+Buyer);
stp.updateFieldValue("/root/domData","TSU_PARTY_NM",Buyer);
stp.SYS_getCUBK("TSU_CUST_NAME","TSU_PARTY_NM","/root/domData/R2InvolvedPartyInfo/Buyer");

var Seller =stp.getValue("/Document/BaselnReSubmissn/Baseln/Sellr","Nm");
var Seller = Seller[0];
stp.writeLog("Seller = "+Seller);
stp.updateFieldValue("/root/domData","TSU_PARTY_NM",Seller);
stp.SYS_getCUBK("TSU_CUST_NAME","TSU_PARTY_NM","/root/domData/R2InvolvedPartyInfo/Seller");

var BillTo =stp.getValue("/Document/BaselnReSubmissn/Baseln/BllTo","Nm");
var BillTo = BillTo[0];
stp.writeLog("BillTo = "+BillTo);
stp.updateFieldValue("/root/domData","TSU_PARTY_NM",BillTo);
if(BillTo!= undefined)
    { stp.writeLog("BillTo");
    stp.SYS_getCUBK("TSU_CUST_NAME","TSU_PARTY_NM","/root/domData/R2InvolvedPartyInfo/BillTo");  
    }

var ShipTo =stp.getValue("/Document/BaselnReSubmissn/Baseln/ShipTo","Nm");
var ShipTo = ShipTo[0];
stp.writeLog("ShipTo = "+ShipTo);
stp.updateFieldValue("/root/domData","TSU_PARTY_NM",ShipTo);
    if(ShipTo!= undefined)
    {
    stp.SYS_getCUBK("TSU_CUST_NAME","TSU_PARTY_NM","/root/domData/R2InvolvedPartyInfo/ShipTo");  
    }	

var Consignee =stp.getValue("/Document/BaselnReSubmissn/Baseln/Consgn","Nm");
var Consignee = Consignee[0];
stp.writeLog("Consignee = "+Consignee);
stp.updateFieldValue("/root/domData","TSU_PARTY_NM",Consignee);
	if(Consignee!= undefined)
    {
    stp.SYS_getCUBK("TSU_CUST_NAME","TSU_PARTY_NM","/root/domData/R2InvolvedPartyInfo/Consignee");  
    }
//Get Buyer/Seller/Bill To/Ship To/Consignee Names -E
var OblgrBk = stp.getValue("/Document/BaselnReSubmissn/Baseln/PmtOblgtn/OblgrBk","BIC");
var RcptBk = stp.getValue("/Document/BaselnReSubmissn/Baseln/PmtOblgtn/RcptBk","BIC");
var nlength = OblgrBk.length;
stp.writeLog("nlength = "+nlength);
if(OblgrBk[0] != undefined)
{
        for(var k=0;k<nlength;k++)
        {
	var OblgrBkk = OblgrBk[k];
	stp.updateFieldValue("/root/domData","TSU_OBLGR_BK",OblgrBkk);
	stp.writeLog("OblgrBkk = "+OblgrBkk);
	stp.SYS_getCUBK("TSU_OBLGR_BK","TSU_OBLGR_BK","/root/domData/R2PaymentObligation["+stp.toDouble(k+1)+"]"); 
	var RcptBkk = RcptBk[k];
	stp.updateFieldValue("/root/domData","TSU_RCPT_BK",RcptBkk);
	stp.writeLog("RcptBkk = "+RcptBkk);
	stp.SYS_getCUBK("TSU_RCPT_BK","TSU_RCPT_BK","/root/domData/R2PaymentObligation["+stp.toDouble(k+1)+"]"); 
	}
}

stp.SYS_getCUBK("TSU_BYRBK_BIC","TSU_BUYER_BK_BIC"); // Get the Buyerbk Name and ID from the Buyer BIC
stp.SYS_getCUBK("TSU_SELLRBK_BIC","TSU_SEL_BK_BIC");      // Get the Sellerbk Name and ID from the Seller BIC
stp.updateFieldValue("/root/domData","TSU_COE_STS","C2B");
